mapper.select:
SELECT id, serial_code, seller_id, seller_name, item_id, item_name, item_amount, current_amount, consume_date, status, consume_type, is_refund, refund_date, remark, create_by, create_time, update_by, update_time, pay_way FROM store_seller_consume where status = 0
and seller_id = #{storeSellerConsumeModel.sellerId}
and serial_code = #{storeSellerConsumeModel.serialCode}
and item_name like CONCAT(CONCAT('%',#{storeSellerConsumeModel.itemName}),'%')
and pay_way = #{storeSellerConsumeModel.payWay}
and consume_type = #{storeSellerConsumeModel.consumeType}
and DATE_FORMAT(consume_date, '%Y-%m-%d') >= DATE_FORMAT(#{storeSellerConsumeModel.startConsumeDate}, '%Y-%m-%d') and DATE_FORMAT(consume_date, '%Y-%m-%d') <= DATE_FORMAT(#{storeSellerConsumeModel.endConsumeDate}, '%Y-%m-%d')
and DATE_FORMAT(consume_date, '%Y-%m-%d') = DATE_FORMAT(#{storeSellerConsumeModel.startConsumeDate}, '%Y-%m-%d')
and DATE_FORMAT(consume_date, '%Y-%m-%d') = DATE_FORMAT(#{storeSellerConsumeModel.endConsumeDate}, '%Y-%m-%d')
order by create_time desc
